export async function getAnonCsrfToken(): Promise<string> {
  const existingToken = readCookie(ANON_CSRF_COOKIE)
  if (existingToken) return existingToken

  anonCsrfTokenRequest ??= authRequest<CsrfResponse>('/csrf-token', { method: 'GET' })
    .then((data) => readCookie(ANON_CSRF_COOKIE) || data.csrf_token)
    .finally(() => {
      anonCsrfTokenRequest = null
    })

  return anonCsrfTokenRequest
}

export async function login(payload: LoginRequest): Promise<LoginResponse> {
  const csrfToken = await getAnonCsrfToken()
  return authRequest<LoginResponse>('/login', {
    method: 'POST',
    headers: {
      'X-CSRF-TOKEN': csrfToken,
    },
    body: JSON.stringify(payload),
  })
}

export async function register(payload: RegisterRequest): Promise<RegisterResponse> {
  const csrfToken = await getAnonCsrfToken()
  return authRequest<RegisterResponse>('/register', {
    method: 'POST',
    headers: {
      'X-CSRF-TOKEN': csrfToken,
    },
    body: JSON.stringify(payload),
  })
}

export function beginGoogleSignIn(): void {
  assertSecureAuthTransport()
  window.location.assign(`${AUTH_BASE_URL}/google/login`)
}

function getAccessCsrfTokenFromCookie(): string {
  const token = readCookie('csrf_access_token')
  if (!token) {
    throw new AuthApiError('Your session has expired. Please sign in again.', 401, null)
  }
  return token
}

function getRefreshCsrfTokenFromCookie(): string {
  const token = readCookie('csrf_refresh_token')
  if (!token) {
    throw new AuthApiError('Your session has expired. Please sign in again.', 401, null)
  }
  return token
}

async function refreshAccessToken(): Promise<void> {
  const refreshCsrfToken = getRefreshCsrfTokenFromCookie()
  await authRequest<{ message: string }>('/refresh', {
    method: 'POST',
    headers: {
      'X-CSRF-TOKEN': refreshCsrfToken,
    },
  })
}

function shouldRefreshAccessToken(error: unknown): boolean {
  if (!(error instanceof AuthApiError)) return false
  if (error.status !== 401) return false
  return error.message !== 'Missing CSRF token' && error.message !== 'CSRF token mismatch'
}

async function requestCurrentUserWithAccessCsrf(csrfToken: string): Promise<UserResponse> {
  return authRequest<UserResponse>('/me', {
    method: 'GET',
    headers: {
      'X-CSRF-TOKEN': csrfToken,
    },
  })
}

export async function getCurrentUser(): Promise<UserResponse> {
  try {
    return await requestCurrentUserWithAccessCsrf(getAccessCsrfTokenFromCookie())
  } catch (error) {
    if (!shouldRefreshAccessToken(error)) {
      throw error
    }
    await refreshAccessToken()
    return requestCurrentUserWithAccessCsrf(getAccessCsrfTokenFromCookie())
  }
}

export async function ensureAccessCsrfToken(): Promise<string> {
  await getCurrentUser()
  return getAccessCsrfTokenFromCookie()
}

async function authRequestWithAccessCsrf<T>(
  requestWithCsrf: (csrfToken: string) => Promise<T>,
): Promise<T> {
  try {
    return await requestWithCsrf(getAccessCsrfTokenFromCookie())
  } catch (error) {
    if (!shouldRefreshAccessToken(error)) {
      throw error
    }
    await refreshAccessToken()
    return requestWithCsrf(getAccessCsrfTokenFromCookie())
  }
}

export async function updateCurrentUsername(username: string): Promise<UserResponse> {
  return authRequestWithAccessCsrf((csrfToken) =>
    authRequest<UserResponse>('/me/username', {
      method: 'PATCH',
      headers: {
        'X-CSRF-TOKEN': csrfToken,
      },
      body: JSON.stringify({ username }),
    }),
  )
}

export async function beginGoogleAccountLink(): Promise<void> {
  assertSecureAuthTransport()
  const result = await authRequestWithAccessCsrf((csrfToken) =>
    authRequest<GoogleLinkStartResponse>('/google/link/start', {
      method: 'POST',
      headers: {
        'X-CSRF-TOKEN': csrfToken,
      },
    }),
  )
  window.location.assign(result.url)
}

export async function unlinkGoogleAccount(): Promise<UserResponse> {
  return authRequestWithAccessCsrf((csrfToken) =>
    authRequest<UserResponse>('/google/unlink', {
      method: 'POST',
      headers: {
        'X-CSRF-TOKEN': csrfToken,
      },
    }),
  )
}

export async function logout(): Promise<void> {
  await authRequestWithAccessCsrf((csrfToken) =>
    authRequest<{ message: string }>('/logout', {
      method: 'POST',
      headers: {
        'X-CSRF-TOKEN': csrfToken,
      },
    }),
  )
}

